body.script:
var ws = new WebSocket('ws://192.168.1.25/ws');

let bg = document.getElementById("bg");
let bpmText = document.getElementById("bpm");
let heart = document.getElementById("heart");

let audioCtx = null;
let audioEnabled = false;

/* ================= AUDIO INIT ================= */

function initAudio(){
    if(!audioEnabled){
        audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        audioEnabled = true;
    }
}

/* ????? ????? ??? click */
document.addEventListener("click", function(){
    initAudio();
});

/* ================= HEART SOUND ================= */

function heartbeatSound(){

    if(!audioEnabled) return;

    let osc = audioCtx.createOscillator();
    let gain = audioCtx.createGain();

    osc.type = "sine";

    osc.frequency.setValueAtTime(140, audioCtx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(60, audioCtx.currentTime + 0.15);

    gain.gain.value = 0.06;

    osc.connect(gain);
    gain.connect(audioCtx.destination);

    osc.start();
    osc.stop(audioCtx.currentTime + 0.15);
}

/* ================= ECG ================= */

let canvas = document.getElementById("ecg");
let ctx = canvas.getContext("2d");

canvas.width = window.innerWidth;
canvas.height = 240;

let x = 0;
let y = 120;

function drawECG(active){

    ctx.strokeStyle = active ? "#ff0033" : "#00ff99";
    ctx.lineWidth = 2;

    let spike = 120;

    if(active){
        let r = Math.random();

        if(r > 0.98) spike = 40;
        else if(r > 0.96) spike = 200;
        else spike = 120 + (Math.random()*6 - 3);
    }

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x+5, spike);
    ctx.stroke();

    y = spike;
    x += 5;

    if(x > canvas.width){
        ctx.clearRect(0,0,canvas.width,canvas.height);
        x = 0;
    }
}

setInterval(()=>drawECG(false),25);

/* ================= WS ================= */

ws.onmessage = function(event){

    let data = event.data;

    if(data.startsWith("FINGER_ON")){

        let bpm = data.split(":")[1];

        bg.style.opacity = "1";

        bpmText.innerHTML = bpm;

        heart.style.opacity = "1";
        heart.classList.add("beat");

        drawECG(true);
        heartbeatSound();

    }else{

        bg.style.opacity = "0";

        heart.style.opacity = "0";
        heart.classList.remove("beat");

        bpmText.innerHTML = "--";
    }
};
